const crypto = require('crypto');

const input = $input.first().json.body ?? $input.first().json;
const requiredFields = [
  'task_id',
  'session_id',
  'task_type',
  'week_start',
  'week_end',
  'callback_url',
  'wr_attach_url',
];

for (const field of requiredFields) {
  if (!input[field]) {
    throw new Error(`Missing required WR payload field: ${field}`);
  }
}

if (input.task_type !== 'weekly_report.interactive.start') {
  throw new Error(`Unsupported task_type for mock WR workflow: ${input.task_type}`);
}

if (!process.env.IMPERIUM_API_BASE_URL) {
  throw new Error('Missing IMPERIUM_API_BASE_URL environment variable.');
}

if (!process.env.INTERNAL_WEBHOOK_SECRET) {
  throw new Error('Missing INTERNAL_WEBHOOK_SECRET environment variable.');
}

const callbackBody = {
  result_type: 'weekly_report.summary',
  result_payload: {
    summary: 'Mock WR summary generated by n8n mock workflow.',
    week_start: input.week_start,
    week_end: input.week_end,
    sections: [
      {
        title: 'Résumé mock',
        content: 'Ce résumé est généré uniquement pour tester le contrat backend ↔ n8n.',
      },
    ],
    questions: [
      'Quel a été le point le plus important de ta semaine ?',
      "Qu'est-ce qui t'a le plus freiné ?",
      'Quelle décision veux-tu prendre pour la semaine prochaine ?',
    ],
  },
  model_used: 'mock-n8n',
  provider: 'n8n-mock',
  confidence: 0.8,
  raw_payload: {
    workflow: 'IMPERIUM_WR_INTERACTIVE_START_MOCK',
    source: 'mock',
  },
};

const rawBody = JSON.stringify(callbackBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto
  .createHmac('sha256', process.env.INTERNAL_WEBHOOK_SECRET)
  .update(message)
  .digest('hex');

return [
  {
    json: {
      ...input,
      aiCallbackRawBody: rawBody,
      aiCallbackTimestamp: timestamp,
      aiCallbackSignature: signature,
      aiCallbackIdempotencyKey: `wr_mock_result_${input.task_id}`,
    },
  },
];

const crypto = require('crypto');

const original = $('Validate Payload and Sign AI Result').first().json;
const callbackResponse = $('POST AI Result Callback').first().json;

if (!callbackResponse.result_id) {
  throw new Error('Backend AI result callback did not return result_id.');
}

const attachBody = {
  ai_result_id: callbackResponse.result_id,
};
const rawBody = JSON.stringify(attachBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto
  .createHmac('sha256', process.env.INTERNAL_WEBHOOK_SECRET)
  .update(message)
  .digest('hex');

return [
  {
    json: {
      session_id: original.session_id,
      wr_attach_url: original.wr_attach_url,
      result_id: callbackResponse.result_id,
      attachRawBody: rawBody,
      attachTimestamp: timestamp,
      attachSignature: signature,
      attachIdempotencyKey: `wr_mock_attach_${original.session_id}_${callbackResponse.result_id}`,
    },
  },
];
